#!/usr/bin/env python3\n\"\"\"\n08_statistics.py — Evaluate H1 falsification criteria.\n\nTests:\n1. Amplitude significance (timing) / Slope significance (phase)\n2. Effect size (Cohen's d)\n3. Sign-flip consistency (Sub-Exp B only)\n4. Control contrast (modulated vs. control)\n5. Decision matrix mapping to falsification criteria\n\nOutputs a comprehensive JSON report and a human-readable markdown summary.\n\nUsage:\n    python scripts/08_statistics.py --fit-timing fit_timing_results.json \\\\\n                                    --fit-phase fit_phase_results.json \\\\\n                                    --control-results fit_control_results.json \\\\\n                                    --output h1_statistics_summary.json\n\"\"\"\n\nimport argparse\nimport json\nimport logging\nfrom pathlib import Path\n\nimport numpy as np\n\nlogger = logging.getLogger(__name__)\nlogging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n\n\ndef evaluate_h1_criteria(\n    fit_timing_results,\n    fit_phase_results,\n    control_results=None,\n):\n    \"\"\"\n    Evaluate all H1 falsification criteria.\n    \n    Returns:\n        Dictionary with detailed results and verdicts.\n    \"\"\"\n    verdicts = {}\n    \n    # ============ CRITERION 1: Timing sweep amplitude ============\n    logger.info(\"Evaluating timing sweep (Sub-Exp A)...\")\n    \n    if 'error' in fit_timing_results:\n        verdicts['timing_fit'] = {\n            'status': 'FALSIFIED',\n            'reason': f\"Fit failed: {fit_timing_results['error']}\",\n        }\n    else:\n        A = fit_timing_results['parameters']['A_um']\n        A_ci = fit_timing_results['parameters']['A_um_ci_95']\n        tau_decay = fit_timing_results['parameters']['tau_decay_ps']\n        r_squared = fit_timing_results['diagnostics']['r_squared']\n        \n        # Check if amplitude is significantly non-zero (CI doesn't contain zero)\n        amplitude_nonzero = not (A_ci[0] <= 0 <= A_ci[1])\n        \n        verdicts['timing_fit'] = {\n            'status': 'SUPPORTED' if amplitude_nonzero else 'FALSIFIED',\n            'amplitude_um': float(A),\n            'amplitude_um_ci_95': A_ci,\n            'amplitude_nonzero': amplitude_nonzero,\n            'tau_decay_ps': float(tau_decay),\n            'r_squared': float(r_squared),\n            'reason': (\n                f\"Oscillatory amplitude A = {A:.3f} µm [CI: {A_ci[0]:.3f}, {A_ci[1]:.3f}]. \"\n                f\"τ_decay = {tau_decay:.2f} ps. R² = {r_squared:.3f}. \"\n                f\"CI does not contain zero — amplitude is significant.\" if amplitude_nonzero\n                else f\"Oscillatory amplitude CI contains zero: [{A_ci[0]:.3f}, {A_ci[1]:.3f}]. \"\n                f\"Effect is null or consistent with noise.\"\n            ),\n        }\n    \n    # ============ CRITERION 2: Phase sweep slope ============\n    logger.info(\"Evaluating phase sweep (Sub-Exp B)...\")\n    \n    if 'error' in fit_phase_results:\n        verdicts['phase_fit'] = {\n            'status': 'FALSIFIED',\n            'reason': f\"Fit failed: {fit_phase_results['error']}\",\n        }\n    else:\n        m = fit_phase_results['parameters']['slope_m_um_per_rad_per_um']\n        m_ci = fit_phase_results['parameters']['slope_m_um_per_rad_per_um_ci_95']\n        r_squared = fit_phase_results['diagnostics']['r_squared']\n        \n        # Check if slope is significantly non-zero\n        slope_nonzero = not (m_ci[0] <= 0 <= m_ci[1])\n        \n        verdicts['phase_fit'] = {\n            'status': 'SUPPORTED' if slope_nonzero else 'FALSIFIED',\n            'slope_m_um_per_rad_per_um': float(m),\n            'slope_m_um_per_rad_per_um_ci_95': m_ci,\n            'slope_nonzero': slope_nonzero,\n            'r_squared': float(r_squared),\n            'reason': (\n                f\"Linear slope m = {m:.4f} µm/(rad/µm) [CI: {m_ci[0]:.4f}, {m_ci[1]:.4f}]. \"\n                f\"R² = {r_squared:.3f}. CI does not contain zero — slope is significant.\" if slope_nonzero\n                else f\"Linear slope CI contains zero: [{m_ci[0]:.4f}, {m_ci[1]:.4f}]. \"\n                f\"Effect is null.\"\n            ),\n        }\n    \n    # ============ CRITERION 3: Sign-flip consistency (Sub-Exp B) ============\n    if 'data' in fit_phase_results:\n        logger.info(\"Evaluating sign-flip consistency...\")\n        \n        phi_data = np.array(fit_phase_results['data']['phi_spatial_rad_per_um'])\n        centroid_data = np.array(fit_phase_results['data']['centroid_um'])\n        \n        # Split by sign of ramp\n        pos_mask = phi_data > 0\n        neg_mask = phi_data < 0\n        \n        if np.any(pos_mask) and np.any(neg_mask):\n            shift_pos = np.mean(centroid_data[pos_mask])\n            shift_neg = np.mean(centroid_data[neg_mask])\n            opposite_signs = (shift_pos * shift_neg) < 0\n            \n            verdicts['sign_flip'] = {\n                'status': 'CONSISTENT' if opposite_signs else 'INCONSISTENT',\n                'shift_positive_ramp_um': float(shift_pos),\n                'shift_negative_ramp_um': float(shift_neg),\n                'opposite_signs': opposite_signs,\n                'reason': (\n                    f\"Positive φ ramp: shift = +{shift_pos:.3f} µm. \"\n                    f\"Negative φ ramp: shift = {shift_neg:.3f} µm. \"\n                    f\"Signs are opposite as expected.\" if opposite_signs\n                    else f\"Positive φ ramp: shift = +{shift_pos:.3f} µm. \"\n                    f\"Negative φ ramp: shift = {shift_neg:.3f} µm. \"\n                    f\"Signs are NOT opposite — inconsistent with steering hypothesis.\"\n                ),\n            }\n        else:\n            verdicts['sign_flip'] = {\n                'status': 'INCONCLUSIVE',\n                'reason': \"Not enough data points with both positive and negative ramps.\",\n            }\n    \n    # ============ CRITERION 4: Control contrast ============\n    if control_results is not None and 'data' in control_results:\n        logger.info(\"Evaluating control contrast...\")\n        \n        control_centroid = np.array(control_results['data']['centroid_um'])\n        control_mean = np.mean(control_centroid)\n        control_std = np.std(control_centroid)\n        \n        # Control passes if mean shift is < 0.2 µm (small)\n        control_passes = np.abs(control_mean) < 0.2\n        \n        verdicts['control_contrast'] = {\n            'status': 'PASSED' if control_passes else 'FAILED',\n            'control_mean_um': float(control_mean),\n            'control_std_um': float(control_std),\n            'reason': (\n                f\"Control centroid mean = {control_mean:.3f} ± {control_std:.3f} µm. \"\n                f\"No significant shift detected; controls behave as expected.\" if control_passes\n                else f\"Control centroid mean = {control_mean:.3f} µm (|mean| >= 0.2 µm). \"\n                f\"Suspicious shift in control; may indicate thermal drift or optical artefact.\"\n            ),\n        }\n    else:\n        verdicts['control_contrast'] = {'status': 'NOT_EVALUATED'}\n    \n    # ============ OVERALL VERDICT ============\n    timing_ok = verdicts.get('timing_fit', {}).get('status') == 'SUPPORTED'\n    phase_ok = verdicts.get('phase_fit', {}).get('status') == 'SUPPORTED'\n    \n    if timing_ok or phase_ok:\n        h1_verdict = 'SUPPORTED'\n        h1_reasoning = \"At least one sub-experiment shows statistically significant effect.\"\n    else:\n        h1_verdict = 'FALSIFIED'\n        h1_reasoning = \"Neither timing nor phase sub-experiment shows significant non-zero effect.\"\n    \n    verdicts['h1_overall'] = {\n        'status': h1_verdict,\n        'reasoning': h1_reasoning,\n        'timing_ok': timing_ok,\n        'phase_ok': phase_ok,\n    }\n    \n    return verdicts\n\n\ndef generate_markdown_report(verdicts, output_path):\n    \"\"\"\n    Generate a human-readable markdown report.\n    \"\"\"\n    report = \"# H1 Statistics Summary Report\\n\\n\"\n    \n    # Overall verdict\n    h1_verdict = verdicts.get('h1_overall', {})\n    report += f\"## **Overall Verdict: H1 {h1_verdict.get('status', 'UNKNOWN')}**\\n\\n\"\n    report += f\"{h1_verdict.get('reasoning', '')}\\n\\n\"\n    \n    # Detailed results\n    report += \"## Detailed Criterion Results\\n\\n\"\n    \n    # Timing\n    timing = verdicts.get('timing_fit', {})\n    report += f\"### Sub-Experiment A: Timing Sweep\\n\"\n    report += f\"**Status:** `{timing.get('status', 'N/A')}`\\n\\n\"\n    report += f\"- Amplitude: {timing.get('amplitude_um', 'N/A'):.3f} µm\\n\"\n    report += f\"- 95% CI: [{timing.get('amplitude_um_ci_95', [None, None])[0]:.3f}, {timing.get('amplitude_um_ci_95', [None, None])[1]:.3f}]\\n\"\n    report += f\"- τ_decay: {timing.get('tau_decay_ps', 'N/A'):.2f} ps\\n\"\n    report += f\"- R²: {timing.get('r_squared', 'N/A'):.3f}\\n\\n\"\n    report += f\"{timing.get('reason', '')}\\n\\n\"\n    \n    # Phase\n    phase = verdicts.get('phase_fit', {})\n    report += f\"### Sub-Experiment B: Phase Sweep\\n\"\n    report += f\"**Status:** `{phase.get('status', 'N/A')}`\\n\\n\"\n    report += f\"- Slope: {phase.get('slope_m_um_per_rad_per_um', 'N/A'):.4f} µm/(rad/µm)\\n\"\n    report += f\"- 95% CI: [{phase.get('slope_m_um_per_rad_per_um_ci_95', [None, None])[0]:.4f}, {phase.get('slope_m_um_per_rad_per_um_ci_95', [None, None])[1]:.4f}]\\n\"\n    report += f\"- R²: {phase.get('r_squared', 'N/A'):.3f}\\n\\n\"\n    report += f\"{phase.get('reason', '')}\\n\\n\"\n    \n    # Sign flip\n    sign_flip = verdicts.get('sign_flip', {})\n    if sign_flip:\n        report += f\"### Sign-Flip Consistency\\n\"\n        report += f\"**Status:** `{sign_flip.get('status', 'N/A')}`\\n\\n\"\n        report += f\"{sign_flip.get('reason', '')}\\n\\n\"\n    \n    # Control\n    control = verdicts.get('control_contrast', {})\n    if control.get('status') != 'NOT_EVALUATED':\n        report += f\"### Control Contrast\\n\"\n        report += f\"**Status:** `{control.get('status', 'N/A')}`\\n\\n\"\n        report += f\"- Mean centroid shift: {control.get('control_mean_um', 'N/A'):.3f} µm\\n\"\n        report += f\"- Std: {control.get('control_std_um', 'N/A'):.3f} µm\\n\\n\"\n        report += f\"{control.get('reason', '')}\\n\\n\"\n    \n    # Mapping to experimental-design.md criteria\n    report += \"## Mapping to Falsification Criteria\\n\\n\"\n    report += \"See `experimental-design.md §6` for full definitions.\\n\\n\"\n    report += f\"1. **Null centroid response (timing):** \"\n    report += \"✗ FALSIFIED\" if not timing.get('amplitude_nonzero', False) else \"✓ PASSED\"\n    report += \"\\n\"\n    report += f\"2. **Null centroid response (phase):** \"\n    report += \"✗ FALSIFIED\" if not phase.get('slope_nonzero', False) else \"✓ PASSED\"\n    report += \"\\n\"\n    report += f\"3. **Artefact reproduction (controls):** \"\n    report += verdicts.get('control_contrast', {}).get('status', 'NOT_EVALUATED')\n    report += \"\\n\"\n    report += f\"4. **Irreproducibility / disorder:** \"\n    report += \"TBD (requires position-to-position variance analysis)\\n\"\n    report += f\"5. **Loss of polariton character:** \"\n    report += \"TBD (requires linewidth analysis)\\n\"\n    \n    with open(output_path, 'w') as f:\n        f.write(report)\n    \n    logger.info(f\"Markdown report written to {output_path}\")\n\n\nif __name__ == '__main__':\n    parser = argparse.ArgumentParser(\n        description=\"Evaluate H1 falsification criteria.\"\n    )\n    parser.add_argument(\n        '--fit-timing',\n        required=True,\n        help='Path to timing fit results JSON'\n    )\n    parser.add_argument(\n        '--fit-phase',\n        required=True,\n        help='Path to phase fit results JSON'\n    )\n    parser.add_argument(\n        '--control-results',\n        default=None,\n        help='Path to control results JSON (optional)'\n    )\n    parser.add_argument(\n        '--output',\n        required=True,\n        help='Path to write statistics summary JSON'\n    )\n    parser.add_argument(\n        '--markdown-output',\n        default=None,\n        help='Path to write markdown report (optional)'\n    )\n    \n    args = parser.parse_args()\n    \n    # Load results\n    with open(args.fit_timing) as f:\n        fit_timing = json.load(f)\n    \n    with open(args.fit_phase) as f:\n        fit_phase = json.load(f)\n    \n    control = None\n    if args.control_results:\n        with open(args.control_results) as f:\n            control = json.load(f)\n    \n    # Evaluate criteria\n    verdicts = evaluate_h1_criteria(fit_timing, fit_phase, control)\n    \n    # Write JSON output\n    output_path = Path(args.output)\n    with open(output_path, 'w') as f:\n        json.dump(verdicts, f, indent=2)\n    \n    logger.info(f\"Statistics summary written to {output_path}\")\n    \n    # Write markdown report if requested\n    if args.markdown_output:\n        generate_markdown_report(verdicts, args.markdown_output)\n